sub extract_text_from_pdf {
    my ($file_path) = @_;
    my $pdf = PDF::API2->open($file_path);

    my $text = '';
    for my $page (1 .. $pdf->pages) {
        $text .= $pdf->page($page)->text;
    }

    return $text;
}

